#!/bin/bash
# Generated by OrchestKit Claude Plugin
# Created: 2026-03-03

# StatusLine context writer — bridges context + rate limits to prompt hooks
#
# CC's StatusLine receives JSON on stdin with:
#   - context_window.used_percentage (all versions)
#   - rate_limits (CC 2.1.80+): 5-hour and 7-day windows with used_percentage and resets_at
#
# This script:
#   1. Reads stdin JSON
#   2. Extracts context_window, session_id, and rate_limits
#   3. Writes context % to {tmpdir}/ork-ctx-pct-{session_id}.txt
#   4. Writes rate limits to {tmpdir}/ork-rate-limits-{session_id}.json
#   5. Outputs StatusLine text to stdout
#
# Bridge pattern: StatusLine → temp file → prompt hooks (context-exhaustion-warner.ts)

set -uo pipefail

# Restrict temp file permissions to owner-only (prevent information leak on multi-user systems)
umask 077

# Read entire stdin into variable
INPUT=$(cat)

# Check jq availability — required for JSON extraction
if ! command -v jq &>/dev/null; then
  BRANCH=$(git branch --show-current 2>/dev/null || echo 'no-git')
  echo "ork | ${BRANCH} | ctx unavailable (no jq)"
  exit 0
fi

# Extract context percentage and session ID (default to 0 / empty if missing)
CTX_PCT=$(echo "$INPUT" | jq -r '.context_window.used_percentage // 0' 2>/dev/null || echo "0")
SESSION_ID=$(echo "$INPUT" | jq -r '.session_id // ""' 2>/dev/null || echo "")

# Extract rate limits (CC 2.1.80+) — gracefully absent on older versions
RATE_USED=$(echo "$INPUT" | jq -r '.rate_limits.used_percentage // empty' 2>/dev/null || echo "")
RATE_RESETS=$(echo "$INPUT" | jq -r '.rate_limits.resets_at // empty' 2>/dev/null || echo "")

# Use $TMPDIR for cross-platform temp dir (defaults to /tmp on macOS/Linux)
TMPDIR="${TMPDIR:-/tmp}"

# Write context percentage to temp file (only if we have a safe session ID)
# Validate session_id: only allow alphanumeric, dots, hyphens, underscores
if [[ -n "$SESSION_ID" && "$SESSION_ID" =~ ^[a-zA-Z0-9._-]+$ ]]; then
  echo "$CTX_PCT" > "${TMPDIR}/ork-ctx-pct-${SESSION_ID}.txt" 2>/dev/null || true

  # Write rate limits JSON if available (CC 2.1.80+)
  if [[ -n "$RATE_USED" ]]; then
    echo "$INPUT" | jq -c '{used_percentage: .rate_limits.used_percentage, resets_at: .rate_limits.resets_at}' \
      > "${TMPDIR}/ork-rate-limits-${SESSION_ID}.json" 2>/dev/null || true
  fi
fi

# Build rate limit display fragment
RATE_FRAGMENT=""
if [[ -n "$RATE_USED" ]]; then
  # Format resets_at as human-readable relative time
  if [[ -n "$RATE_RESETS" && "$RATE_RESETS" != "null" ]]; then
    RATE_FRAGMENT=" | rate ${RATE_USED}%"
  else
    RATE_FRAGMENT=" | rate ${RATE_USED}%"
  fi
fi

# Output StatusLine text
VERSION=$(jq -r .version package.json 2>/dev/null || echo '?')
BRANCH=$(git branch --show-current 2>/dev/null || echo 'no-git')
UNCOMMITTED=$(git status --porcelain 2>/dev/null | wc -l | tr -d ' ')

echo "ork v${VERSION} | ${BRANCH} | ${UNCOMMITTED} uncommitted | ctx ${CTX_PCT}%${RATE_FRAGMENT}"
